{:version=>3, :sections=>[{:offset=>{:line=>0, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/game_system/NervWhitePaper.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule BCDice\n  module GameSystem\n    class NervWhitePaper < Base\n      # ゲームシステムの識別子\n      ID = 'NervWhitePaper'\n\n      # ゲームシステム名\n      NAME = '新世紀エヴァンゲリオンRPG NERV白書/使徒降臨'\n\n      # ゲームシステム名の読みがな\n      SORT_KEY = 'しんせいきえうあんけりおんああるひいしいねるふはくしよしとこおりん'\n\n      # ダイスボットの使い方\n      HELP_MESSAGE = <<~INFO_MESSAGETEXT\n        ■通常ロール(NR)：成功、失敗、絶対成功、絶対失敗を表示します。\n        例) NR\n\n        ■長所ロール(NA)：成功、失敗、絶対成功、絶対失敗を表示します。\n        例) NA\n\n        ■短所ロール(ND)：成功、失敗、絶対成功、絶対失敗を表示します。\n        例) ND\n\n      INFO_MESSAGETEXT\n\n      register_prefix('N[RAD]')\n\n      def eval_game_system_specific_command(command)\n        resolute_regular_action(command) ||\n          resolute_advantage_action(command) ||\n          resolute_disadvantage_action(command)\n      end\n\n      private\n\n      # 通常ロールによる判定\n      # @param [String] command\n      # @return [Result]\n      def resolute_regular_action(command)\n        m = /NR/.match(command)\n        return nil unless m\n\n        dices = @randomizer.roll_barabara(2, 6)\n        dice_text = dices.join(\",\")\n        dice_add = dices.sum\n\n        output = \"(NR) ＞ \#{dice_text}\"\n\n        if dice_add == 7\n          output += \" ＞ 絶対成功\"\n          return Result.critical(output)\n        elsif dice_add == 2\n          output += \" ＞ 絶対失敗\"\n          return Result.fumble(output)\n        elsif dice_add == 12\n          output += \" ＞ 絶対失敗\"\n          return Result.fumble(output)\n        elsif dice_add.modulo(2) == 0\n          output += \" ＞ 失敗\"\n          return Result.failure(output)\n        else\n          output += \" ＞ 成功\"\n          return Result.success(output)\n        end\n      end\n\n      # 長所ロールによる判定\n      # @param [String] command\n      # @return [Result]\n      def resolute_advantage_action(command)\n        m = /NA/.match(command)\n        return nil unless m\n\n        dices = @randomizer.roll_barabara(2, 6)\n        dice_text = dices.join(\",\")\n        dice_add = dices.sum\n\n        output = \"(NA) ＞ \#{dice_text}\"\n\n        if dice_add == 7\n          output += \" ＞ 絶対成功\"\n          return Result.critical(output)\n        elsif dice_add == 2\n          output += \" ＞ 絶対失敗\"\n          return Result.fumble(output)\n        elsif dice_add == 12\n          output += \" ＞ 絶対失敗\"\n          return Result.fumble(output)\n        elsif dices[0] == dices[1]\n          output += \" ＞ 失敗\"\n          return Result.failure(output)\n        else\n          output += \" ＞ 成功\"\n          return Result.success(output)\n        end\n      end\n\n      # 短所ロールによる判定\n      # @param [String] command\n      # @return [Result]\n      def resolute_disadvantage_action(command)\n        m = /ND/.match(command)\n        return nil unless m\n\n        dices = @randomizer.roll_barabara(2, 6)\n        dice_text = dices.join(\",\")\n        dice_add = dices.sum\n\n        output = \"(ND) ＞ \#{dice_text}\"\n\n        if dice_add == 7\n          output += \" ＞ 絶対成功\"\n          return Result.critical(output)\n        elsif dice_add == 2\n          output += \" ＞ 絶対失敗\"\n          return Result.fumble(output)\n        elsif dice_add == 12\n          output += \" ＞ 絶対失敗\"\n          return Result.fumble(output)\n        elsif dice_add != 7\n          output += \" ＞ 失敗\"\n          return Result.failure(output)\n        end\n      end\n    end\n  end\nend\n"], :names=>["<main>", "<module:BCDice>", "<module:GameSystem>", "<class:NervWhitePaper>", "self", "register_prefix", "eval_game_system_specific_command", "command", "$ret_or_1", "$ret_or_2", "resolute_regular_action", "resolute_advantage_action", "resolute_disadvantage_action", "private", "m", "match", "dices", "@randomizer", "roll_barabara", "2", "6", "dice_text", "join", "dice_add", "sum", "output", "7", "+", "Result", "critical", "fumble", "12", "modulo", "0", "failure", "success", "[]", "1", "Base"], :mappings=>"AAAAA,2BAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;AAAAA;;QAEE,8BAAKA,gBAAL;QAGA,gCAAOA,4BAAP;QAGA,oCAAWA,mCAAX;QAGA,wCACNA,qCADqB,GAErBA,SAFqB,GAGrBA,IAHqB,GAIrBA,qCAJqB,GAKrBA,SALqB,GAMrBA,IANqB,GAOrBA,qCAPqB,GAQrBA,SARqB,GASrBA,IATM;QAYAC,IAAAC,iBAAAA,CAAgBF,QAAhBE;;AAEAC,QAAAA,iDAAAA,6CAAsCC,OAAtCD;AAAAA,UAAAA;;UACE,IAAA,QAAAE,CAAAA,YAAA,CAAA,QAAAC,CAAAA,YAAAL,IAAAM,yBAAAA,CAAwBH,OAAxBG,CAAAD,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CACEL,IAAAO,2BAAAA,CAA0BJ,OAA1BI,CADF,CAAA,CAAAH,CAAA,CAAA;YAAAF,OAAA;UAAA;YAEEA,OAAAF,IAAAQ,8BAAAA,CAA6BL,OAA7BK;UAFF;QADFN,CAAAA;QAMAF,IAAAS,SAAAA,CAAAA;;AAKAH,QAAAA,uCAAAA,mCAA4BH,OAA5BG;AAAAA,UAAAA;;;UACEI,IAAI,IAAIC,OAAAA,CAAOR,OAAPQ;UACR,KAAA,QAAkBD,CAAlB,CAAA;YAAA,OAAO;UAAP;UAEAE,QAAQC,eAAWC,eAAAA,CAAeC,CAA1B,EAA6BC,CAAlBF;UACnBG,YAAYL,KAAKM,MAAAA,CAAMZ,GAANY;UACjBC,WAAWP,KAAKQ,KAAAA,CAAAA;UAEhBC,SAAUf,SAAD,GAAA,CAAUW,SAAV;UAET,IAAA,MAAGE,QAAH,EAAeG,CAAf,CAAA;;YACED,SAAOE,SAAPF,MAAOE,EAAGjB,SAAHiB;YACP,OAAOC,YAAMC,UAAAA,CAAUJ,MAAVI;UAFf,OAGA,IAAA,MAAMN,QAAN,EAAkBJ,CAAlB,CAAA;;YACEM,SAAOE,SAAPF,MAAOE,EAAGjB,SAAHiB;YACP,OAAOC,YAAME,QAAAA,CAAQL,MAARK;UAFf,OAGA,IAAA,MAAMP,QAAN,EAAkBQ,EAAlB,CAAA;;YACEN,SAAOE,SAAPF,MAAOE,EAAGjB,SAAHiB;YACP,OAAOC,YAAME,QAAAA,CAAQL,MAARK;UAFf,OAGA,IAAA,MAAMP,QAAQS,QAAAA,CAAQb,CAARa,CAAd,EAA4BC,CAA5B,CAAA;;YACER,SAAOE,SAAPF,MAAOE,EAAGjB,OAAHiB;YACP,OAAOC,YAAMM,SAAAA,CAAST,MAATS;UAFf;;YAIET,SAAOE,SAAPF,MAAOE,EAAGjB,OAAHiB;YACP,OAAOC,YAAMO,SAAAA,CAASV,MAATU;UALf;QAnBFzB,CAAAA;;AA+BAC,QAAAA,yCAAAA,qCAA8BJ,OAA9BI;AAAAA,UAAAA;;;UACEG,IAAI,IAAIC,OAAAA,CAAOR,OAAPQ;UACR,KAAA,QAAkBD,CAAlB,CAAA;YAAA,OAAO;UAAP;UAEAE,QAAQC,eAAWC,eAAAA,CAAeC,CAA1B,EAA6BC,CAAlBF;UACnBG,YAAYL,KAAKM,MAAAA,CAAMX,GAANW;UACjBC,WAAWP,KAAKQ,KAAAA,CAAAA;UAEhBC,SAAUd,SAAD,GAAA,CAAUU,SAAV;UAET,IAAA,MAAGE,QAAH,EAAeG,CAAf,CAAA;;YACED,SAAOE,SAAPF,MAAOE,EAAGhB,SAAHgB;YACP,OAAOC,YAAMC,UAAAA,CAAUJ,MAAVI;UAFf,OAGA,IAAA,MAAMN,QAA